const pendingOrders=computed(()=>orders.filter(o=>['결제완료','배송준비'].includes(o.status)).length), paidOrders=computed(()=>orders.filter(o=>o.status==='결제완료').length)
const orderTabs=['전체','결제완료','배송준비','배송중','배송완료','취소요청']
const filteredOrders=computed(()=>orders.filter(o=>(orderFilter.value==='전체'||o.status===orderFilter.value)&&`${o.id}${o.name}${o.product}`.toLowerCase().includes(orderSearch.value.toLowerCase())))
const filteredProducts=computed(()=>products.filter(p=>(productStatus.value==='전체 상태'||p.status===productStatus.value)&&`${p.name}${p.sku}`.toLowerCase().includes(productSearch.value.toLowerCase())))
const inventoryProducts=computed(()=>(stockOnly.value?filteredProducts.value.filter(p=>p.stock<=5):filteredProducts.value))
const filteredCustomers=computed(()=>customers.filter(c=>`${c.name}${c.email}${c.phone}`.toLowerCase().includes(customerSearch.value.toLowerCase())))
const today=new Intl.DateTimeFormat('ko-KR',{year:'numeric',month:'long',day:'numeric',weekday:'long'}).format(new Date())
const newProduct=reactive({name:'',category:'의류',sku:'',price:0,stock:0,image:''})
function won(n){return `₩${Number(n).toLocaleString()}`}
function selectView(id){activeView.value=id;menuOpen.value=false;window.scrollTo({top:0,behavior:'smooth'})}
function goOrders(filter){orderFilter.value=filter;selectView('orders')}
function orderCount(tab){return tab==='전체'?orders.length:orders.filter(o=>o.status===tab).length}
function statusClass(s){return s==='판매중'?'live':s==='품절'?'sold':'hidden'}
function cycleProductStatus(p){p.status=p.status==='판매중'?'숨김':p.status==='숨김'?(p.stock?'판매중':'품절'):'숨김';notify(`${p.name} 상태를 ${p.status}(으)로 변경했습니다.`)}
function changeOrderStatus({order,status}){order.status=status;notify(`${order.id} 주문을 ${status}(으)로 변경했습니다.`)}
function adjustStock(p,delta){p.stock=Math.max(0,p.stock+delta);if(p.stock===0)p.status='품절';else if(p.status==='품절')p.status='판매중'}
function openProductModal(){Object.assign(newProduct,{name:'',category:'의류',sku:'',price:0,stock:0,image:''});productModal.value=true}
function saveProduct(){products.unshift({name:newProduct.name,category:newProduct.category,price:Number(newProduct.price),stock:Number(newProduct.stock),sku:newProduct.sku||`${shop.initial}-${Date.now().toString().slice(-6)}`,image:newProduct.image||images[0],status:Number(newProduct.stock)>0?'판매중':'품절',updated:'방금 전'});productModal.value=false;notify('새 상품을 등록했습니다.')}
let toastTimer
function notify(message){toast.value=message;clearTimeout(toastTimer);toastTimer=setTimeout(()=>toast.value='',2600)}
</script>

